use std::sync::{Arc, Mutex};
use std::thread;
use std::time::Duration;

struct JobResult {
    processed_count: i32,
    last_successful_job: String,
}

fn main() {
    let shared_data = Arc::new(Mutex::new(JobResult {
        processed_count: 0,
        last_successful_job: String::from("None"),
    }));

    let num_threads = 5;
    let mut handles = vec![];

    for i in 1..=num_threads {
        let data_clone = Arc::clone(&shared_data);
        let handle = thread::spawn(move || {
            println!("Thread {} starting work.", i);
            thread::sleep(Duration::from_millis(50 * (i % 3 + 1)));

            { 
                let mut data = data_clone.lock().unwrap();
                data.processed_count += 1;
                data.last_successful_job = format!("Job-{}", i);
                println!("Thread {} updated shared count to {}", i, data.processed_count);
            }
            thread::sleep(Duration::from_millis(50));
        });
        handles.push(handle);
    }

    for handle in handles {
        handle.join().unwrap();
    }

    let final_result = shared_data.lock().unwrap();
    println!("n--- All Jobs Complete ---n");
    println!("Final Processed Count: {}", final_result.processed_count);
    println!("Last Job Reported: {}", final_result.last_successful_job);
}

use std::thread;
use std::time::Duration;

struct Record {
    id: u32,
    data: String,
}

fn process_record(record: Record) -> Result<String, &'static str> {
    if record.data.is_empty() {
        return Err("Missing data field");
    }
    println!("Processing record {}: Start", record.id);
    thread::sleep(Duration::from_millis(100));
    Ok(format!("Successfully processed ID {}", record.id))
}

fn main() {
    let records = vec![ 
        Record { id: 1, data: "Alpha".to_string() },
        Record { id: 2, data: "Beta".to_string() },
        Record { id: 3, data: "Gamma".to_string() },
    ];

    let mut handles = vec![];

    for record in records {
        let handle = thread::spawn(move || -> Result<String, &'static str> {
            process_record(record)
        });
        handles.push(handle);
    }

    println!("Main thread waiting for workers...");

    let mut results = vec![];
    for handle in handles {
        match handle.join() {
            Ok(result) => match result {
                Ok(data) => results.push(data),
                Err(e) => println!("Thread error: {}", e),
            },
            Err(_) => println!("Join failed for a thread"),
        }
    }

    println!("nAll records processed. Total results: {}", results.len());
}

