use std::thread;
use std::time::Duration;

fn process_markdown(content: String) -> String {
    println!("Processing content on thread...");
    thread::sleep(Duration::from_millis(50));
    format!(r#"<div class="rendered-html">{}</div>"#, content.to_uppercase())
}

fn main() {
    let sections = vec![
        "# Title: My Awesome PagenThis is the first chunk.",
        "## Section 2nAnother piece of content to render.",
        "### Footer ContentnFinal block for processing.",
    ];

    let mut handles = vec![];

    for section in sections {
        let data = String::from(section);
        let handle = thread::spawn(move || {
            process_markdown(data)
        });
        handles.push(handle);
    }

    let mut rendered_blocks = Vec::new();

    for handle in handles {
        match handle.join() {
            Ok(html) => rendered_blocks.push(html),
            Err(_) => println!("A thread panicked!")
        }
    }

    println!("n--- All rendering complete ---");
    for block in rendered_blocks {
        println!("{}", block);
    }
}

use std::thread;
use std::time::Duration;

struct PluginState {
    id: u32,
    isRunning: bool,
}

fn simulate_plugin_execution(state: &PluginState) -> i32 {
    println!("Starting background task for plugin {}", state.id);
    thread::sleep(Duration::from_millis((100 + (state.id % 3) * 50) as u64));
    let result = state.id as i32 * 2;
    println!("Finished background task for plugin {}", state.id);
    result
}

fn main() {
    let plugins_to_run: Vec<PluginState> = vec![
        PluginState { id: 1, isRunning: true },
        PluginState { id: 2, isRunning: true },
        PluginState { id: 3, isRunning: true },
    ];

    let mut handles = vec![];

    for plugin_state in plugins_to_run {
        let handle = thread::spawn(move || {
            simulate_plugin_execution(&plugin_state)
        });
        handles.push(handle);
    }

    let mut final_results = vec![];

    for handle in handles {
        match handle.join() {
            Ok(result) => final_results.push(result),
            Err(_) => println!("A task panicked and failed.")
        }
    }

    println!("nAll background tasks complete. Final processed results: {:?}", final_results);
}
